@page "/courses"
@using CourseCatalog.Services
@using CourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" class="row g-3 mb-4" data-enhance>
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search"
               value="@Search" placeholder="Search by title, code, or keyword…" />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select class="form-select" id="department" name="department">
            <option value="">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id" selected="@(dept.Id == Department)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (Department is not null && _activeDepartment is not null)
{
    <div class="alert alert-info d-flex justify-content-between align-items-center">
        <span>Showing courses in <strong>@_activeDepartment.Name</strong></span>
        <a href="/courses@(string.IsNullOrEmpty(Search) ? "" : $"?search={Search}")" class="btn btn-sm btn-outline-secondary">Clear Filter</a>
    </div>
}

@if (_courses.Count == 0)
{
    <div class="alert alert-warning">No courses found matching your criteria.</div>
}
else
{
    <p class="text-muted mb-3">@_courses.Count course(s) found</p>
    <div class="row">
        @foreach (var course in _courses)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@course.Code</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                        <p class="card-text small">@course.Schedule.Days · @course.Schedule.Time</p>
                        <span class="badge bg-secondary me-1">@course.Credits credits</span>
                        <span class="badge bg-info text-dark">@GetDepartmentName(course.DepartmentId)</span>
                    </div>
                    <div class="card-footer bg-transparent d-flex justify-content-between">
                        <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a>
                        <a href="/enroll?courseId=@course.Id" class="btn btn-outline-success btn-sm">Enroll</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public string? Department { get; set; }

    private List<Course> _courses = [];
    private List<Department> _departments = [];
    private Department? _activeDepartment;

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _courses = Catalog.GetCourses(Department, Search);
        _activeDepartment = Department is not null ? Catalog.GetDepartment(Department) : null;
    }

    private string GetDepartmentName(string deptId) =>
        _departments.FirstOrDefault(d => d.Id == deptId)?.Name ?? deptId;
}

@page "/enroll"
@using CourseCatalog.Services
@using CourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Request Enrollment</h1>
<p class="text-muted">Fill out the form below to submit an enrollment request. You will receive a confirmation email once your request is processed.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>
            Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
            <strong>@(_selectedCourse?.Code) – @(_selectedCourse?.Title)</strong>
            has been received.
        </p>
        <hr />
        <p class="mb-0">You will be notified via your university email once the request is reviewed.</p>
    </div>
    <a href="/enroll" class="btn btn-outline-primary">Submit Another Request</a>
}
else
{
    <form method="post" class="needs-validation" @formname="enrollment" data-enhance>
        <AntiforgeryToken />

        <div class="row">
            <div class="col-md-6 mb-3">
                <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" id="studentName" name="_model.StudentName"
                       value="@_model.StudentName" required placeholder="e.g. Jane Doe" />
            </div>

            <div class="col-md-6 mb-3">
                <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                <input type="text" class="form-control" id="studentId" name="_model.StudentId"
                       value="@_model.StudentId" required placeholder="e.g. S12345678"
                       pattern="S\d{8}" title="Student ID must start with 'S' followed by 8 digits" />
            </div>
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
            <select class="form-select" id="courseId" name="_model.CourseId" required>
                <option value="">— Select a course —</option>
                @foreach (var course in _courses)
                {
                    <option value="@course.Id" selected="@(course.Id == _model.CourseId)">
                        @course.Code – @course.Title (@course.Credits cr)
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest _model { get; set; } = new();
    [SupplyParameterFromQuery] public string? CourseId { get; set; }

    private List<Course> _courses = [];
    private bool _submitted;
    private Course? _selectedCourse;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (!string.IsNullOrEmpty(CourseId) && string.IsNullOrEmpty(_model.CourseId))
            _model.CourseId = CourseId;

        _submitted = HttpMethods.IsPost(_httpContext.Request.Method)
                     && !string.IsNullOrWhiteSpace(_model.StudentName)
                     && !string.IsNullOrWhiteSpace(_model.StudentId)
                     && !string.IsNullOrWhiteSpace(_model.CourseId);

        if (_submitted)
            _selectedCourse = Catalog.GetCourse(_model.CourseId);
    }

    [CascadingParameter] private HttpContext _httpContext { get; set; } = default!;
}

